fun solve(s: String): Array<String> {
    val segments = mutableListOf<String>()
    val seen = mutableSetOf<String>()
    val currentSegment = mutableListOf<Char>()
    var i = 0

    while (i < s.length) {
        currentSegment.add(s[i])
        val currentStr = currentSegment.joinToString("")
        if (currentStr !in seen) {
            seen.add(currentStr)
            i++
        } else {
            currentSegment.clear()
            i++
        }
    }

    if (currentSegment.isNotEmpty()) {
        segments.add(currentSegment.joinToString(""))
    }

    return segments.toTypedArray()
}
